                ? 'bg-slate-400 cursor-not-allowed' 
                : 'bg-teal-600 hover:bg-teal-700 text-white shadow-teal-100'
            }`}
          >
            {status === 'submitting' ? (
              <>전송 중... <Loader2 size={18} className="animate-spin" /></>
