            </div>
          )}

          {status === 'error' && (
            <div className="flex items-center gap-2 text-red-600 bg-red-50 p-4 rounded-xl animate-in fade-in slide-in-from-top-2">
              <AlertCircle size={20} />
              <span className="text-sm font-bold">오류가 발생했습니다. 잠시 후 다시 시도해 주세요.</span>
            </div>
          )}
        </form>
      </div>
    </div>
  );
};

